commits.content:
.modal {
    display:none;
    position:fixed;
    top:0;
    left:0;
    width:100%;
    height:100%;

    background:rgba(0,0,0,0.5);

    justify-content:center;
    align-items:center;

    z-index:9999;
}

.modal-content {
    background:white;
    padding:20px;
    border-radius:12px;

    width:300px;

    box-shadow:0 10px 25px rgba(0,0,0,0.2);
}

.modal-content h3 {
    margin-top:0;
}

.modal-content select,
.modal-content input {
    width:100%;
    padding:10px;
    margin-top:8px;

    border:1px solid #ddd;
    border-radius:8px;
}

.modal-content button {
    padding:8px 12px;
    border:none;
    border-radius:8px;
    cursor:pointer;
}

.modal-content button:last-child {
    background:#16a34a;
    color:white;
}.modal-message {
    display: none;
}
